import React, { useState } from 'react';
import LanguageSwitcher from './LanguageSwitcher';

function Payment({ plan, onSuccess, onCancel }) {
  const [phone, setPhone] = useState('');
  const [code, setCode] = useState('');
  const [step, setStep] = useState(1);

  const prices = { monthly: 3000, yearly: 15000 };
  const price = prices[plan] || 3000;

  const sendCode = () => {
    if (phone.length < 10) return alert('📱 Numéro invalide');
    const random = Math.floor(100000 + Math.random() * 900000);
    setCode(random);
    alert(`📲 Code envoyé à ${phone}\nCode: ${random}\nMontant: ${price} DA`);
    setStep(2);
  };

  const verify = () => {
    const input = prompt('📲 Entrez le code reçu:');
    if (input === String(code)) {
      alert('✅ Paiement réussi');
      onSuccess();
    } else {
      alert('❌ Code incorrect');
    }
  };

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        <button onClick={onCancel} style={styles.closeBtn}>✕</button>
        <h2>💳 Paiement بريدي موب</h2>
        <LanguageSwitcher />
        <p style={styles.price}>{price} DA</p>
        {step === 1 ? (
          <>
            <input type="tel" placeholder="📱 0555123456" value={phone} onChange={(e) => setPhone(e.target.value)} style={styles.input} />
            <button onClick={sendCode} style={styles.sendBtn}>📲 Envoyer le code</button>
          </>
        ) : (
          <button onClick={verify} style={styles.verifyBtn}>🔑 Vérifier le code</button>
        )}
      </div>
    </div>
  );
}

const styles = {
  overlay: { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 },
  modal: { background: 'white', borderRadius: 30, padding: 40, maxWidth: 400, width: '100%', textAlign: 'center' },
  closeBtn: { float: 'right', background: 'none', border: 'none', fontSize: 24, cursor: 'pointer' },
  price: { fontSize: '2rem', color: '#FF1493' },
  input: { width: '100%', padding: 12, borderRadius: 12, border: '2px solid #ddd', fontSize: '1rem', marginTop: 10, boxSizing: 'border-box' },
  sendBtn: { width: '100%', padding: 14, marginTop: 15, background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', border: 'none', borderRadius: 12, fontWeight: 'bold', cursor: 'pointer' },
  verifyBtn: { width: '100%', padding: 14, background: '#4CAF50', color: 'white', border: 'none', borderRadius: 12, fontWeight: 'bold', cursor: 'pointer' },
};

export default Payment;
